import pika
import subprocess
import os

def callback(ch, method, properties, body):
    try:
        command = body.decode('utf-8')
        print(f" [x] Received command: '{command}'")

        # Execute the command using subprocess.run
        # For security, ensure that the commands coming from the queue are trusted.
        # Shell=True is used here as per the request, but be extremely cautious.
        # Consider a whitelist of allowed commands or a safer execution strategy.
        result = subprocess.run(
            command,
            shell=True,
            capture_output=True,
            text=True,
            check=False # Do not raise an exception for non-zero exit codes
        )

        print(f" [x] Command '{command}' finished.")
        print(f"     STDOUT: {result.stdout.strip()}")
        print(f"     STDERR: {result.stderr.strip()}")
        print(f"     Exit Code: {result.returncode}")

        # Acknowledge the message only after successful processing
        ch.basic_ack(delivery_tag=method.delivery_tag)
        print(f" [x] Acknowledged message: '{command}'")

    except Exception as e:
        print(f" [!] Error processing message: {e}")
        # Optionally, NACK the message to requeue it or move it to a dead-letter queue
        # ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
        # For now, we'll acknowledge even on error to prevent infinite loops if the error is persistent
        # and to avoid blocking the queue. In a real system, you'd want a more robust error handling
        # including dead-lettering or retry logic.
        ch.basic_ack(delivery_tag=method.delivery_tag)
        print(f" [!] Acknowledged error message to prevent blocking.")


if __name__ == '__main__':
    RABBITMQ_HOST = os.getenv('RABBITMQ_HOST', 'localhost')
    RABBITMQ_QUEUE = os.getenv('RABBITMQ_QUEUE', 'task_queue')

    print(f" [!] Connecting to RabbitMQ host: {RABBITMQ_HOST}")
    connection = pika.BlockingConnection(pika.ConnectionParameters(host=RABBITMQ_HOST))
    channel = connection.channel()

    # Declare the queue, ensuring it's durable
    channel.queue_declare(queue=RABBITMQ_QUEUE, durable=True)

    # Set prefetch count to 1, so the consumer only gets one message at a time
    # and processes it before getting another one. This is important for long-running tasks.
    channel.basic_qos(prefetch_count=1)

    print(f' [*] Waiting for messages in queue "{RABBITMQ_QUEUE}". To exit press CTRL+C')

    channel.basic_consume(queue=RABBITMQ_QUEUE, on_message_callback=callback)

    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        print(' [x] Consumer stopped by user.')
        channel.stop_consuming()
    finally:
        connection.close()
        print(' [x] RabbitMQ connection closed.')